// Extract idea data from webhook payload
const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    ideaId: body.ideaId,
    title: body.title,
    description: body.description || '',
    verdict: body.verdict,
    scores: body.scores || {},
    sourceUrl: body.sourceUrl || ''
  }
}];

// Parse Claude response and extract product data
const response = $input.first().json;
let product = null;

try {
  if (response.content && response.content[0] && response.content[0].text) {
    const text = response.content[0].text.trim();
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) product = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  return [{ json: { error: 'Failed to parse Claude response', raw: response } }];
}

if (!product) return [{ json: { error: 'No product data generated' } }];

const ideaData = $('Извлечь данные идеи').item.json;

return [{
  json: {
    ...product,
    ideaId: ideaData.ideaId,
    ideaTitle: ideaData.title,
    generatedAt: new Date().toISOString(),
    status: 'generated'
  }
}];

// Save landing page HTML and product brief to disk
const fs = require('fs');
const path = require('path');
const product = $input.first().json;

if (product.error) return [{ json: product }];

// Create project folder
const slug = (product.productName || 'product').toLowerCase().replace(/[^a-z0-9]/g, '-');
const projectDir = `C:/autonomy-launches/${slug}`;

if (!fs.existsSync(projectDir)) {
  fs.mkdirSync(projectDir, { recursive: true });
}

// Save landing page HTML
if (product.landingPageHtml) {
  fs.writeFileSync(`${projectDir}/index.html`, product.landingPageHtml, 'utf8');
}

// Save product brief JSON
const brief = { ...product };
delete brief.landingPageHtml;
fs.writeFileSync(`${projectDir}/brief.json`, JSON.stringify(brief, null, 2), 'utf8');

// Save README
const readme = `# ${product.productName}\n\n${product.tagline}\n\n## Problem\n${product.problem}\n\n## Solution\n${product.solution}\n\n## Target Audience\n${product.targetAudience}\n\n## Tech Stack\n${(product.techStack || []).join(', ')}\n\n## MVP Steps\n${(product.mvpSteps || []).map(s => `- **${s.day}**: ${s.task}`).join('\n')}\n\n## Launch Checklist\n- [ ] Buy domain: ${product.domain}\n- [ ] Set up Next.js project\n- [ ] Deploy to Vercel\n- [ ] Connect Stripe\n- [ ] Launch on ProductHunt\n`;
fs.writeFileSync(`${projectDir}/README.md`, readme, 'utf8');

// Update launches registry
const registryPath = 'C:/autonomy-data/launches.json';
let launches = [];
try {
  launches = JSON.parse(fs.readFileSync(registryPath, 'utf8'));
} catch(e) {}

launches.push({
  id: Date.now(),
  ideaId: product.ideaId,
  ideaTitle: product.ideaTitle,
  productName: product.productName,
  tagline: product.tagline,
  slug,
  status: 'generated',
  projectDir,
  generatedAt: product.generatedAt
});

if (!fs.existsSync('C:/autonomy-data')) fs.mkdirSync('C:/autonomy-data', { recursive: true });
fs.writeFileSync(registryPath, JSON.stringify(launches, null, 2), 'utf8');

return [{
  json: {
    success: true,
    productName: product.productName,
    tagline: product.tagline,
    slug,
    projectDir,
    landingPageUrl: `file:///${projectDir}/index.html`,
    domain: product.domain,
    generatedAt: product.generatedAt
  }
}];
